  "root_causes": [
    {
      "type": "Configuration (administrative)",
      "cause": "R2 Serial0/1/0 is administratively shut, causing the link to go down on R2.",
      "evidence": [
        "get_interface_status(router2): \"admin_state\": \"down\", \"oper_state\": \"down\", \"last_change\": \"2026-05-26T09:30:23.000086+00:00\"",
        "get_running_config(router2): Serial0/1/0 entry contains \"shutdown\"",
        "get_ospf(router2): Serial0/1/0 interface_state = \"Down\""
      ],
      "confidence": 0.95
    },
    {
      "type": "Remote-affected local interface (operational)",
      "cause": "R1 Serial0/1/0 is administratively up but its line protocol went to lower-layer-down because the remote peer (R2) is administratively down/unavailable.",
      "evidence": [
        "get_interface_status(router1): \"admin_state\": \"up\", \"oper_state\": \"lower-layer-down\", \"last_change\": \"2026-05-26T09:30:26.00069+00:00\"",
        "get_interface_status(router2): neighbor admin down (see above) — explains why R1's operational state dropped to lower-layer-down",
        "get_ospf(router1): Serial0/1/0 interface_state = \"Down\" and no neighbors"
      ],
      "confidence": 0.9
    }
  ],
  "missing_info": []
}

{
  "intent": "check_and_fix",
  "intent_description": "R2 Serial0/1/0 is administratively down, causing the serial link to go down on R2 and R1 (R1 oper state = lower-layer-down). Remediate by bringing R2 Serial0/1/0 admin state to up to restore the link and OSPF adjacency.",
  "target": "R1,R2",
  "needs_fix": true,
  "plan": {
    "problem": "R2 Serial0/1/0 is administratively shut (running-config contains 'shutdown'), resulting in R2 oper_state=down and R1 oper_state=lower-layer-down; OSPF adjacency on that interface is down.",
    "fix_summary": "Clear administrative shutdown on R2 Serial0/1/0 (set admin_state to up) to restore the serial link and OSPF adjacency. Risk: brief interface flap and routing reconvergence during the change.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/0",
        "parameters": [
          "admin_state=up"
        ]
      }
    ]
  }
}
